package com.chaobo.scm.supplier.infrastructure.persistence.profile;import org.apache.ibatis.annotations.*;import java.time.OffsetDateTime;
@Mapper public interface AdmissionRegistrationProjectionMapper{@Insert("INSERT INTO sup_admission_registration(admission_id,supplier_id,supplier_code,registration_status,source_event_code,source_version,registered_at) VALUES(#{admissionId},#{supplierId},#{supplierCode},1,#{eventCode},#{sourceVersion},#{occurredAt}) ON DUPLICATE KEY UPDATE supplier_id=IF(source_version&lt;=VALUES(source_version),VALUES(supplier_id),supplier_id),supplier_code=IF(source_version&lt;=VALUES(source_version),VALUES(supplier_code),supplier_code),registration_status=IF(source_version&lt;=VALUES(source_version),1,registration_status),source_version=GREATEST(source_version,VALUES(source_version)),registered_at=IF(source_version&lt;=VALUES(source_version),VALUES(registered_at),registered_at)")void registered(@Param("admissionId")long admissionId,@Param("supplierId")long supplierId,@Param("supplierCode")String supplierCode,@Param("eventCode")String eventCode,@Param("sourceVersion")long sourceVersion,@Param("occurredAt")OffsetDateTime occurredAt);}
